Here are pytest-style unit tests written in plain text (no Markdown or code fences). You can copy them directly into a test file such as test_zip_dicts.py.

from pytest import raises

from your_module import zip_dicts


def test_zip_dicts_happy_path():
    d1 = {"a": 1, "b": 2}
    d2 = {"a": 10, "b": 20}
    result = zip_dicts(d1, d2)
    assert result == {"a": [1, 10], "b": [2, 20]}


def test_zip_dicts_different_keys():
    d1 = {"a": 1, "b": 2}
    d2 = {"b": 3, "c": 4}
    result = zip_dicts(d1, d2)
    assert result == {
        "a": [1, None],   # missing from d2
        "b": [2, 3],
        "c": [None, 4],   # missing from d1
    }


def test_zip_dicts_single_dict():
    d1 = {"x": 5}
    result = zip_dicts(d1)
    assert result == {"x": [5]}


def test_zip_dicts_no_dicts():
    result = zip_dicts()
    # Union of no dicts = empty set; result should be empty dict
    assert result == {}


def test_zip_dicts_with_empty_dicts():
    d1 = {}
    d2 = {}
    result = zip_dicts(d1, d2)
    assert result == {}


def test_zip_dicts_handles_None_values():
    d1 = {"a": None}
    d2 = {"a": 3}
    result = zip_dicts(d1, d2)
    assert result == {"a": [None, 3]}


def test_zip_dicts_non_dict_input_error():
    # The function will break when set().union(*dicts) receives non-dict
    with raises(TypeError):
        zip_dicts({"a": 1}, ["not a dict"])
